        [@ocaml.doc
          "The branch, tag, HEAD, or other fully qualified reference used to identify a commit (for example, a branch name or a full commit ID)."];
      destinationCommitSpecifier: CommitName.t
        [@ocaml.doc
          "The branch, tag, HEAD, or other fully qualified reference used to identify a commit (for example, a branch name or a full commit ID)."];
      targetBranch: BranchName.t option
        [@ocaml.doc "The branch where the merge is applied."];
      conflictDetailLevel: ConflictDetailLevelTypeEnum.t option
        [@ocaml.doc
          "The level of conflict detail to use. If unspecified, the default FILE_LEVEL is used, which returns a not-mergeable result if the same file has differences in both branches. If LINE_LEVEL is specified, a conflict is considered not mergeable if the same file in both branches has differences on the same line."];
      conflictResolutionStrategy: ConflictResolutionStrategyTypeEnum.t option
        [@ocaml.doc
          "Specifies which branch to use when resolving conflicts, or whether to attempt automatically merging two versions of a file. The default is NONE, which requires any conflicts to be resolved manually before the merge operation is successful."];
      authorName: Name.t option
        [@ocaml.doc
          "The name of the author who created the commit. This information is used as both the author and committer for the commit."];
      email: Email.t option
        [@ocaml.doc
          "The email address of the person merging the branches. This information is used in the commit information for the merge."];
      commitMessage: Message.t option
        [@ocaml.doc
          "The commit message to include in the commit information for the merge."];
      keepEmptyFolders: KeepEmptyFolders.t option
        [@ocaml.doc
          "If the commit contains deletions, whether to keep a folder or folder structure if the changes leave the folders empty. If true, a .gitkeep file is created for empty folders. The default is false."];
      conflictResolution: ConflictResolution.t option
        [@ocaml.doc
          "If AUTOMERGE is the conflict resolution strategy, a list of inputs to use when resolving conflicts during a merge."]}
