    let make ?targetBranch =
      fun ?conflictDetailLevel ->
        fun ?conflictResolutionStrategy ->
          fun ?authorName ->
            fun ?email ->
              fun ?commitMessage ->
                fun ?keepEmptyFolders ->
                  fun ?conflictResolution ->
                    fun ~repositoryName ->
